package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidPathAndCharset() throws Exception {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Create a spy of csvFormat to override print(Appendable)
        CSVFormat spyFormat = spy(csvFormat);

        // When print(Appendable) is called, return mockPrinter
        doReturn(mockPrinter).when(spyFormat).print(any(Appendable.class));

        // Create a subclass of CSVFormat overriding print(Path, Charset) to avoid calling Files.newBufferedWriter
        CSVFormat testFormat = createCSVFormatSubclass() {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                return print(new StringWriter());
            }
        };

        CSVFormat spyTestFormat = spy(testFormat);
        doReturn(mockPrinter).when(spyTestFormat).print(any(Appendable.class));

        CSVPrinter result = spyTestFormat.print(mockPath, StandardCharsets.UTF_8);

        assertNotNull(result);
        verify(spyTestFormat).print(any(Appendable.class));
    }

    @Test
    void testPrintThrowsIOExceptionWhenFilesNewBufferedWriterFails() throws IOException {
        Path mockPath = mock(Path.class);

        // Create a subclass to simulate IOException on print(Path, Charset)
        CSVFormat testFormat = createCSVFormatSubclass() {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                throw new IOException("File write error");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> testFormat.print(mockPath, StandardCharsets.UTF_8));
        assertEquals("File write error", thrown.getMessage());
    }

    /**
     * Helper method to create an anonymous subclass of CSVFormat using reflection to invoke the package-private constructor.
     */
    private CSVFormat createCSVFormatSubclass() {
        try {
            Constructor<CSVFormat> ctor = CSVFormat.class.getDeclaredConstructor(
                    char.class, Character.class, QuoteMode.class, Character.class, Character.class,
                    boolean.class, boolean.class, String.class, String.class, Object[].class,
                    String[].class, boolean.class, boolean.class, boolean.class, boolean.class,
                    boolean.class, boolean.class);
            ctor.setAccessible(true);
            return ctor.newInstance(
                    CSVFormat.DEFAULT.getDelimiter(),
                    CSVFormat.DEFAULT.getQuoteCharacter(),
                    CSVFormat.DEFAULT.getQuoteMode(),
                    CSVFormat.DEFAULT.getCommentMarker(),
                    CSVFormat.DEFAULT.getEscapeCharacter(),
                    CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(),
                    CSVFormat.DEFAULT.getIgnoreEmptyLines(),
                    CSVFormat.DEFAULT.getRecordSeparator(),
                    CSVFormat.DEFAULT.getNullString(),
                    null,
                    CSVFormat.DEFAULT.getHeader(),
                    CSVFormat.DEFAULT.getSkipHeaderRecord(),
                    CSVFormat.DEFAULT.getAllowMissingColumnNames(),
                    CSVFormat.DEFAULT.getIgnoreHeaderCase(),
                    CSVFormat.DEFAULT.getTrim(),
                    CSVFormat.DEFAULT.getTrailingDelimiter(),
                    CSVFormat.DEFAULT.getAutoFlush()
            );
        } catch (NoSuchMethodException | SecurityException | InstantiationException | IllegalAccessException | InvocationTargetException e) {
            throw new RuntimeException("Failed to create CSVFormat subclass instance", e);
        }
    }
}
